    ("७ ऑगस्ट 1942 रोजी कोणत्या ठिकाणी सर्व‑इंडिया काँग्रेस सत्र झाले?", ["लोहगढ, पुणे", "ग्वालियर टँक (क्रिकट) ग्राउंड, मुंबई", "कोल्कत्ता सिटी हॉल", "लाहोर पॅलेस"], 1, "हे अधिवेशन गवालिया टँक मैदान, मुंबई येथे झाले."),
    ("आजाद दस्ता काय करीत होते?", ["बँक लूटणे", "रेल्वे व टेलिफोन वायर्सचे खंडन करणे", "शस्त्रास्त्र उत्पादन", "राजनैतिक सभा आयोजित करणे"], 1, "ब्रिटिशांची दळणवळण व्यवस्था विस्कळीत करण्याचे काम."),
    ("आजाद दस्त्याचे संस्थापक कोण होते?", ["भाऊ कोतवाल", "राव कडू", "स्वराज बाई", "सतीश कुमार"], 0, "महाराष्ट्रातील रायगड जिल्ह्यात भाई कोतवाल यांनी आझाद दस्ता स्थापना केली."),
    ("लाल सेना काय कार्य करती?", ["शस्त्रधारी हल्ले व चोरवाया करणे", "शैक्षणिक वर्ग चालवणे", "कृषी सुधारणा करणे", "राजकीय प्रचार करणे"], 0, "सशस्त्र कारवाया आणि भूमिगत कार्यकर्त्यांना मदत."),
    ("आझाद रेडिओचे संस्थापक कोण होते?", ["विठाल जावडे & उषा मेहता", "राजेशवर्गीय शंकर", "लता मंगेशकर", "भीमसिंह राव"], 0, "उषा मेहता आणि विठ्ठल जवेरी यांनी 'आझाद रेडिओ' चालवला."),
    ("तुफान सेनेचे मुख्य कार्य काय होते?", ["कर वसुली व स्थानिक न्यायालयांची स्थापना", "सागरी नौकेंचे संरक्षण", "विदेशी दूतांचे स्वागत", "शैक्षणिक प्रशिक्षण"], 0, "कायदा राखणे, कर गोळा करणे आणि पर्यायी न्यायालये चालवणे."),
    ("प्रतीसारकार (पॅरॅलल गव्हर्नमेंट) कुठे स्थापन केले?", ["सॅन्ट्रल बेंगलुरु", "सातारा, १९४२", "कोलकाता, १९४५", "दिल्ली, १९४१"], 1, "क्रांतिसिंह नाना पाटील यांनी सातारा जिल्ह्यात 'प्रतीसरकार' स्थापन केले."),
    ("‘प्रतीसारकार’चा अर्थ काय आहे?", ["पूर्ण स्वायत्त सरकार", "ब्रिटिशांच्या अधीन राहणारी प्रशासकीय व्यवस्था", "जिंकल्यानंतर स्थापित केलेला स्थानिक सरकार", "अर्ध-स्वायत्त, परदेशी समर्थन असलेला सरकार"], 2, "ब्रिटिश प्रशासनाला समांतर असे स्वतःचे स्वतंत्र सरकार."),
    ("‘आझाद दस्ता’चे इंग्रजी अर्थ काय आहे?", ["स्वतंत्र सेना", "स्वातंत्र्य दल", "स्वेच्छाचारी गट", "मुक्त बँड"], 1, "याचा अर्थ फ्रीडम स्क्वाड किंवा स्वातंत्र्य दल असा होतो."),
    ("फॉरवर्ड ब्लॉकची स्थापना केव्हा व कोणी केली?", ["1939, सुभाष चंद्र बोस", "1942, महात्मा गांधी", "1945, नेहरू", "1935, जवाहरलाल नेहुरू"], 0, "1939 मध्ये सुभाषचंद्र बोस यांनी स्थापना केली."),
    ("फॉरवर्ड ब्लॉकचे उद्दिष्ट काय होते?", ["अधिक माइल्ड राजकीय कार्यक्रम बनवणे", "ब्रिटिशांसोबत सहकार्य वाढवणे", "सशस्त्र प्रतिकारासाठी जनमत उभारणे", "आर्थिक विकासावर लक्ष केंद्रित करणे"], 2, "सशस्त्र क्रांतीची तयारी करणे हे मुख्य उद्दिष्ट होते."),
    ("बोसने ब्रिटिशांसोबत कोणत्या प्रकारचे सहकार्य नाकारले?", ["आर्थिक सहयोग", "लष्करी सहयोग", "राजकीय संवाद", "सर्व प्रकारचे सहकार्य"], 3, "बोस यांनी ब्रिटिशांशी सर्व प्रकारचे सहकार्य नाकारले."),
    ("बोसने 1941 मध्ये कोणत्या देशात ‘Free India Centre’ स्थापन केले?", ["जपान", "जर्मनी", "इटली", "फ्रान्स"], 1, "एप्रिल 1941 मध्ये बर्लिन, जर्मनी येथे सुरू केले."),
    ("‘Berlin Radio Appeal’ चे महत्त्व काय होते?", ["भारतीयांना शांतीचे आवाहन करणे", "सशस्त्र संघर्षासाठी आह्वान करणे", "व्यापार करार जाहीर करणे", "शैक्षणिक कार्यक्रम प्रसारित करणे"], 1, "सशस्त्र लढा उभारण्याचे ऐतिहासिक आवाहन."),
    ("जपानमध्ये बोसने कोणत्या नेत्यासोबत पॅन‑एशियन फ्रंट तयार करण्याचा विचार केला?", ["रशभारी बोस", "झोऊ एन्ली", "त्सुनेमोतो यासुकी", "लिआओ शुंग"], 0, "रासबिहारी बोस यांच्याशी चर्चा केली."),
    ("इंडियन इंडिपेंडन्स लीग (IIL) चे संस्थापक कोण होते?", ["सुभाष चंद्र बोस", "रशभारी बोस", "मोहन सिंह", "राजगुरु"], 1, "रासबिहारी बोस यांनी IIL ची स्थापना केली."),
    ("IIL चे सह‑आयोजक कोणी होते?", ["कर्नल डॉ. राजेंद्र", "कॅप्टन मोहन सिंह", "लॅड्ज. सर अॅडम्स", "जनरल अॅडम स्मिथ"], 1, "कॅप्टन मोहन सिंह सह-आयोजक होते."),
    ("बोसने INA ला काय नाव दिले?", ["भारतीय स्वातंत्र्य सेना", "आजाद हिंद फौज", "भारत रक्षा दल", "स्वराज्य सेना"], 1, "1943 मध्ये त्यांनी 'आझाद हिंद फौज' हे नाव दिले."),
    ("INA मधील महिलांच्या रेगिमेंटचे नाव काय होते?", ["झशी रानी", "सुभाष रानी", "अॅनांटा", "कॅरोलिना"], 0, "'झाशीची राणी रेजिमेंट' नावाची तुकडी होती."),
    ("जापानींनी अँडमन व निकोबार द्वीपसमूह कधी जिंकले?", ["नोव्हेंबर 1943", "ऑगस्ट 1942", "मार्च 1945", "जानेवारी 1944"], 0, "नोव्हेंबर 1943 मध्ये हे जिंकून आझाद हिंद सरकारला दिले."),
    ("बोसने अँडमन व निकोबारला काय नाव दिले?", ["“शहिद” (अँडमन) आणि “स्वराज्य” (निकोबार)", "“स्वतंत्र” आणि “सशक्त”", "“नवभारत” आणि “नवजागरण”", "“एकता” आणि “समृद्धी”"], 0, "त्यांनी शहिद आणि स्वराज्य ही नावे दिली."),
    ("INA खटल्यांमध्ये मोहन सिंहचा बचाव कोण करीत होते?", ["जवाहरलाल नेहुरू, भुलाभाई देशाई, तेज बहादुर सप्रू", "सरदार पटेल, मोतीलाल नेहरू, अंबरनाथ", "डॉ. बाबासाहेब आंबेडकर, राजेन्द्र प्रसाद, सुभाष बोस", "लाला लजपत राय, बाल गंगाधर टिलक, पंडित जवाहरलाल"], 0, "काँग्रेसच्या दिग्गज वकिलांनी अधिकाऱ्यांचा बचाव केला."),
    ("INA खटल्यांतील प्रारंभिक निर्णय काय होता?", ["सर्वांना आजीवन कारावास", "मृत्युदंड (नंतर रद्द)", "माफ़ीची घोषणा", "फक्त दंड"], 1, "सुरुवातीला फाशीची शिक्षा होती, पण प्रक्षोभामुळे रद्द झाली."),
    ("सार्वजनिक आंदोलनाने INA खटल्यांच्या परिणामावर काय प्रभाव टाकला?", ["खटले अधिक कठोर झाले", "मृत्युदंड कायम राहिला", "बहुतेक दोषींची शिक्षा रद्द झाली", "खटल्यांवर कोणताही परिणाम नव्हता"], 2, "जनतेच्या दबावामुळे शिक्षा रद्द करावी लागली."),
    ("1946 च्या नौसैनिक बंडाचे मध्यवर्ती कारण काय होते?", ["वेतन वाढीचा प्रश्न", "इंग्रजांच्या राजीनाम्याची मागणी", "तिरंगा ध्वज उचलून आदेश नाकारणे", "विदेशी व्यापाराविरुद्ध निषेध"], 2, "नौसैनिकांनी ब्रिटिश ध्वज उतरवून तिरंगा फडकवला व आदेश नाकारले."),
    ("HM Talwar बंड कधी सुरू झाले?", ["18 फेब्रुवारी 1946", "1 मार्च 1946", "15 एप्रिल 1946", "30 मे 1946"], 0, "HMIS तलवार या जहाजावर 18 फेब्रुवारी रोजी बंड सुरू झाले."),
    ("बंडात सहभागी झालेल्या इतर किती जहाजांवर ते पसरले?", ["3", "5", "9", "12"], 2, "हे बंड इतर 9 जहाजांवरही पसरले."),
    ("नौसैनिक बंडात कोणत्या शहरांच्या एअर‑फोर्स युनिट्सनीही सहभागी होऊन समर्थन दिले?", ["कोलकाता, चेन्नई, बेंगळूरू", "दिल्ली, कराची, अंबाला", "लाहोर, रायलि, जयपूर", "अहमदाबाद, इंदौर, पुणे"], 1, "दिल्ली, कराची आणि अंबाला येथील युनिट्सनी समर्थन दिले."),
    ("सदर बंडावर सर्दार पटेल यांनी काय आश्वासन दिले?", ["त्वरित स्वातंत्र्याची घोषणा", "राजकीय सुधारणा आणि पगारवाढ", "ब्रिटिशांसोबतचा करार समाप्त करणे", "सैनिकांच्या सर्व मागण्यांची पूर्तता"], 1, "राजकीय सुधारणांचे आश्वासन देऊन बंड शांत केले."),
    ("सुभाष चंद्र बोसची मृत्यूची तारीख काय होती?", ["15 एप्रिल 1945", "18 ऑगस्ट 1945", "2 सप्टेंबर 1945", "30 डिसेंबर 1945"], 1, "18 ऑगस्ट 1945 रोजी त्यांचा मृत्यू झाला."),
    ("बोस कुठे आणि कशा प्रकारे मृत्यू पावला?", ["हाँगकाँग, जहाजविक्षेपात", "टायवान (फॉर्मोसा), विमान अपघातात", "जर्मनी, रॉकेट प्रयोगात", "जपान, समुद्रात बुडाल्याने"], 1, "तैवान येथे विमान अपघातात त्यांचा मृत्यू झाला."),
    ("बोसचा प्रसिद्ध वाक्य “Give me blood, and I will give you freedom.” चे मराठी रूप काय आहे?", ["“माझ्यासाठी रक्त द्या, मी तुम्हाला स्वातंत्र्य देईन.”", "“रक्ताची किंमत न देता स्वातंत्र्य मिळत नाही.”", "“रक्त देऊ, स्वातंत्र्य मिळेल.”", "“रक्त द्या, स्वातंत्र्य मिळवा.”"], 0, "“माझ्यासाठी रक्त द्या, मी तुम्हाला स्वातंत्र्य देईन.”"),
    ("बोसने फॉरवर्ड ब्लॉकच्या 1940 च्या भाषणात काय म्हटले?", ["“आपला संघर्ष सर्व युद्धांपेक्षा कठोर असावा.”", "“आपले उद्दिष्ट फक्त आर्थिक स्वावलंबन आहे.”", "“ब्रिटिशांसोबत वाटाघाटी सर्वात चांगला मार्ग आहे.”", "“शांतिपूर्ण प्रदर्शन हेच यशस्वी मार्ग आहे.”"], 0, "त्यांनी संघर्ष कठोर असावा असे आवाहन केले."),
    ("क्विट इण्डिया चळवळीची इतर पूर्वीच्या अहिंसक आंदोलनांपेक्षा प्रमुख वैशिष्ट्य काय होते?", ["फक्त शस्त्रबंदी वापरणे", "पूर्ण स्वातंत्र्याची मागणी व दहशतवादाचा वापर", "व्यापक जनसामूहिक सवत्रा आणि त्वरित ब्रीटिश निर्गमनाची मागणी", "फक्त राजकीय दलांचे बैठका"], 2, "त्वरित ब्रिटिश निर्गमनाची मागणी होती."),
    ("जागतिक परिस्थितीने भारतीय नेते शस्त्रसंधीला का वळवले?", ["द्वितीय महायुद्धातील ब्रिटिश दुर्बलता", "चीनसोबतचा व्यापार करार", "अमेरिकेची आर्थिक मदत", "सोविएत युनियनचा प्रतिकार"], 0, "दुसऱ्या महायुद्धामुळे ब्रिटिशांची दुर्बलता वाढली होती."),
    ("Quit India काळातील दोन भूमिगत गटांचे नाव सांगा, ज्यांनी सॅबोटाज केली.", ["आजाद दस्ता, लॅल सेना", "स्वराज सेना, राष्ट्रीय फौज", "फ्री इंडिया क्लब, युवा मोर्चा", "जनतेचा पंथ, मुक्ती संघ"], 0, "आझाद दस्ता आणि लाल सेना यांनी ब्रिटिशांविरुद्ध भूमिगत कारवाई केली."),
